#include<bits/stdc++.h>
using namespace std;
int a[301],dp[500010],dp1[500010];
int main()
{
    int n;
    scanf("%d",&n);
    dp[0]=1;
    dp1[0]=1;
    int sum=0;
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
        sum+=a[i];
    }
    int m=sum>>1;
    for(int i=1;i<=n;i++)
    {
        for(int j=m;j>=a[i];j--)
        {
            dp[j]+=dp[j-a[i]];
            dp[j]%=1000000;
            dp1[j]|=dp1[j-a[i]];
        }
    }
    for(int i=m;i>=1;i--)
    {
        if(dp1[i])
        {
            printf("%d\n%d",abs(sum-2*i),dp[i]);
            return 0;
        }
    }
    return 0;
}
